def double_all(numbers):
    result = []
    for i in range(len(numbers)):
        result.append(numbers[i] * 2)
    return result

def find_min(numbers):
    if not numbers:
        return None
    best = numbers[0]
    for n in numbers[1:]:
        if n < best:
            best = n
    return best

def average(numbers):
    total = 0
    for n in numbers:
        total += n
    return total / len(numbers)

def count_words(text):
    words = text.split()
    return len(words)

def binary_search(arr, target):
    low, high = 0, len(arr) - 1
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1
